// ─────────────────────────────────────────
//  CASE MODE — Difficulty picker logic
// ─────────────────────────────────────────
const difficultyConfig = {
  beginner:     { label: 'Beginner',     icon: '🌱' },
  intermediate: { label: 'Intermediate', icon: '⚡' },
  advanced:     { label: 'Advanced',     icon: '🔬' },
  expert:       { label: 'Expert',       icon: '🏥' }
};

let currentDifficulty = null;
let lastCaseId = null;
let caseAnswered = false;

function initDiffCounts() {
  ['beginner', 'intermediate', 'advanced', 'expert'].forEach(diff => {
    const count = cases.filter(c => c.difficulty === diff).length;
    const el = document.getElementById('diffCount-' + diff);
    if (el) el.textContent = count + ' case' + (count !== 1 ? 's' : '');
  });
}

function startRandomCase(difficulty) {
  currentDifficulty = difficulty;
  const pool = cases.filter(c => c.difficulty === difficulty);
  if (!pool.length) return;
  let available = pool.filter(c => c.id !== lastCaseId);
  if (!available.length) available = pool;
  const c = available[Math.floor(Math.random() * available.length)];
  lastCaseId = c.id;

  caseAnswered = false;
  document.getElementById('case-difficulty-picker').classList.add('hidden');
  document.getElementById('case-detail').classList.remove('hidden');

  const cfg = difficultyConfig[difficulty];
  document.getElementById('caseTag').textContent = c.tag;
  document.getElementById('caseDiffBadge').textContent = cfg.icon + ' ' + cfg.label;
  document.getElementById('caseDiffBadge').className = 'case-diff-badge diff-badge--' + difficulty;
  document.getElementById('caseTitle').textContent = c.title;
  document.getElementById('caseScenario').textContent = c.scenario;
  document.getElementById('casePatient').textContent = c.patient;
  document.getElementById('caseComplaint').textContent = c.complaint;
  document.getElementById('caseBackground').textContent = c.background;

  document.getElementById('caseChoices').innerHTML = c.choices.map((ch, ci) => `
    <button class="choice-btn" onclick="selectChoice(this, ${ch.correct}, ${ci})">${ch.text}</button>
  `).join('');

  document.getElementById('caseExplanation').classList.add('hidden');
  document.getElementById('nextCaseBtn').style.display = 'none';
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

function selectChoice(btn, isCorrect, idx) {
  if (caseAnswered) return;
  caseAnswered = true;
  const c = cases.find(x => x.id === lastCaseId);
  const btns = document.querySelectorAll('.choice-btn');
  btns.forEach((b, i) => {
    b.disabled = true;
    if (c.choices[i].correct) b.classList.add('correct');
  });
  if (!isCorrect) btn.classList.add('incorrect');
  document.getElementById('expText').textContent = c.explanation;
  document.getElementById('learnMore').innerHTML = `<strong>🔑 Key Terms to Explore</strong> ${c.learnMore}`;
  document.getElementById('caseExplanation').classList.remove('hidden');
  document.getElementById('nextCaseBtn').style.display = 'inline-block';
  recordCaseAnswer(c.id, isCorrect, c.tag, c.difficulty);
}

function nextRandomCase() {
  startRandomCase(currentDifficulty);
}

function backToDiffPicker() {
  document.getElementById('case-difficulty-picker').classList.remove('hidden');
  document.getElementById('case-detail').classList.add('hidden');
}

