// ─── EMBEDDED ANATOMY IMAGES (base64, no internet required) ───────
const ANAT_IMGS = {
  heart: 'data:image/png;base64,',
  respiratory: 'data:image/png;base64,',
  nervous: 'data:image/png;base64,',
  digestive: 'data:image/png;base64,',
  skeletal: 'data:image/png;base64,',
  lungs_sub: 'data:image/png;base64,',
  intestines_sub: 'data:image/png;base64,',
};

// Fallback for any image that still fails to decode
function anatImgError(img) {
  img.style.display = 'none';
  img.parentNode.querySelector('.anat-img-error').style.display = 'flex';
}

// Invisible hover-glow — no visible dot, just soft colour on hover
function _zone(l) {
  var action = l.sub ? "openSubDiagram('" + l.sub + "')" : "openPart('" + l.id + "')";
  var r = l.sub ? 11 : 8;
  return '<g onclick="' + action + '" class="anat-hotspot" style="cursor:pointer;">'
       + '<circle cx="' + l.cx + '" cy="' + l.cy + '" r="' + r + '" fill="' + l.color + '" class="anat-glow"/>'
       + '</g>';
}

function _svgOverlay(labels) {
  return '<svg viewBox="0 0 100 100" preserveAspectRatio="none"'
       + ' style="position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;overflow:visible;">'
       + '<g style="pointer-events:all;">' + labels.map(_zone).join('') + '</g></svg>';
}

function makeDiagram(imgKey, alt, credit, labels) {
  return '<div class="anat-img-wrap">'
       + '<img src="' + ANAT_IMGS[imgKey] + '" alt="' + alt + '" class="anat-real-img"'
       + ' onerror="anatImgError(this)"/>'
       + '<div class="anat-img-error">Image unavailable.</div>'
       + _svgOverlay(labels)
       + '</div><p class="anat-diagram-credit">🖼 ' + credit + '</p>';
}

function makeSubDiagram(imgKey, alt, credit, labels, title) {
  return '<div class="anat-sub-header">'
       + '<button class="anat-sub-back-btn" onclick="restoreSystemDiagram()">← Back to overview</button>'
       + '<span class="anat-sub-title">' + title + '</span></div>'
       + '<div class="anat-img-wrap">'
       + '<img src="' + ANAT_IMGS[imgKey] + '" alt="' + alt + '" class="anat-real-img"'
       + ' onerror="anatImgError(this)"/>'
       + '<div class="anat-img-error">Image unavailable.</div>'
       + _svgOverlay(labels)
       + '</div><p class="anat-diagram-credit">🖼 ' + credit + '</p>';
}

