// ── NAVIGATION ────────────────────────────────────────────────────────────────

function openSubDiagram(subId) {
  var html = getSubDiagram(subId);
  if (!html) return;
  document.getElementById('anatDiagramContainer').innerHTML = html;
  document.getElementById('anatDiagramContainer').scrollIntoView({ behavior:'smooth', block:'start' });
}

function restoreSystemDiagram() {
  document.getElementById('anatDiagramContainer').innerHTML = getSystemDiagram(currentSystemId);
}



// ─────────────────────────────────────────
//  ANATOMY NAVIGATION
// ─────────────────────────────────────────

let currentSystemId = null;

function renderSystemList() {
  const grid = document.getElementById('systemGrid');
  grid.innerHTML = systems.map((s, i) => `
    <button class="system-card" onclick="openSystem(${i})">
      <div class="system-icon">${s.icon}</div>
      <div class="system-name">${s.name}</div>
      <div class="system-hint">${s.hint}</div>
    </button>
  `).join('');
}

function openSystem(index) {
  const s = systems[index];
  currentSystemId = s.id;
  document.getElementById('anatomy-list').classList.add('hidden');
  document.getElementById('anatomy-part').classList.add('hidden');
  document.getElementById('anatomy-system').classList.remove('hidden');
  document.getElementById('anatSysIcon').textContent = s.icon;
  document.getElementById('anatSysTitle').textContent = s.name;
  document.getElementById('anatSysOverview').textContent = s.overview;
  document.getElementById('anatSysSpecialties').innerHTML = s.specialties.map(sp => `<span class="specialty-tag">${sp}</span>`).join('');
  document.getElementById('anatSysFact').textContent = s.fact;
  document.getElementById('anatDiagramContainer').innerHTML = getSystemDiagram(s.id);
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

function openPart(partId) {
  const p = anatomyParts[partId];
  if (!p) return;
  document.getElementById('anatomy-system').classList.add('hidden');
  document.getElementById('anatomy-part').classList.remove('hidden');
  const sys = systems.find(s => s.id === p.system);
  document.getElementById('anatPartBadge').textContent = sys ? sys.icon + ' ' + sys.name : '';
  document.getElementById('anatPartTitle').textContent = p.name;
  document.getElementById('anatPartSubtitle').textContent = p.subtitle;
  document.getElementById('anatTabOverview').innerHTML = `<div class="anat-tab-text">${p.overview}</div>`;
  document.getElementById('anatTabDiseases').innerHTML = p.diseases.map(d => `
    <div class="anat-disease-card">
      <div class="anat-disease-name">${d.name}</div>
      <p>${d.desc}</p>
      ${d.source ? `<div class="anat-disease-source">📚 ${d.source}</div>` : ''}
    </div>`).join('');
  document.getElementById('anatTabProcedures').innerHTML = p.procedures.map(pr => `
    <div class="anat-procedure-card">
      <div class="anat-procedure-name">🔧 ${pr.name}</div>
      <p>${pr.desc}</p>
    </div>`).join('');
  document.getElementById('anatTabFacts').innerHTML = `<ul class="anat-facts-list">${p.facts.map(f => `<li>${f}</li>`).join('')}</ul>`;
  document.getElementById('anatPartSource').innerHTML = `<strong>📖 Sources:</strong> ${p.source}`;
  document.querySelectorAll('.anat-tab').forEach(t => t.classList.remove('active'));
  document.querySelectorAll('.anat-tab-content').forEach(c => c.classList.add('hidden'));
  document.querySelector('.anat-tab').classList.add('active');
  document.getElementById('anatTabOverview').classList.remove('hidden');
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

function switchAnatTab(btn, tabName) {
  document.querySelectorAll('.anat-tab').forEach(t => t.classList.remove('active'));
  document.querySelectorAll('.anat-tab-content').forEach(c => c.classList.add('hidden'));
  btn.classList.add('active');
  document.getElementById('anatTab' + tabName.charAt(0).toUpperCase() + tabName.slice(1)).classList.remove('hidden');
}

function backToSystem() {
  document.getElementById('anatomy-part').classList.add('hidden');
  document.getElementById('anatomy-system').classList.remove('hidden');
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

function backToAnatomyList() {
  document.getElementById('anatomy-list').classList.remove('hidden');
  document.getElementById('anatomy-system').classList.add('hidden');
  document.getElementById('anatomy-part').classList.add('hidden');
  currentSystemId = null;
}
