const allCategories = ['All', 'Saved ⭐', ...new Set(flashcards.map(f => f.cat))];
let fcFiltered = [...flashcards];
let fcIndex = 0;
let fcFlipped = false;
let fcActiveCategory = 'All';

// ── SRS Data ──────────────────────────────
// srsData[term] = { status: 'unseen'|'learning'|'know', interval: N, nextReview: timestamp, saveCount: N }
// savedCards: Set of terms
let srsData = {};
let savedCards = new Set();

function srsKey(term) { return 'srs_' + term; }

function loadSRS() {
  try {
    const raw = localStorage.getItem('medpath_srs');
    if (raw) srsData = JSON.parse(raw);
    const rawSaved = localStorage.getItem('medpath_saved');
    if (rawSaved) savedCards = new Set(JSON.parse(rawSaved));
  } catch(e) { srsData = {}; savedCards = new Set(); }
}

function saveSRS() {
  try {
    localStorage.setItem('medpath_srs', JSON.stringify(srsData));
    localStorage.setItem('medpath_saved', JSON.stringify([...savedCards]));
  } catch(e) {}
}

function getCardData(term) {
  return srsData[term] || { status: 'unseen', interval: 1, nextReview: 0, reps: 0 };
}

// SM-2-inspired: "know" doubles interval (capped at 60 days), "learning" resets to 1 day
function rateCard(rating) {
  const card = fcFiltered[fcIndex];
  if (!card) return;
  const data = getCardData(card.term);
  const now = Date.now();

  if (rating === 'know') {
    data.status = 'know';
    data.reps = (data.reps || 0) + 1;
    // Interval doubles each correct answer: 1 → 2 → 4 → 8 … capped at 60
    data.interval = Math.min((data.interval || 1) * 2, 60);
    data.nextReview = now + data.interval * 86400000;
  } else {
    data.status = 'learning';
    data.reps = 0;
    data.interval = 1; // back to 1 day
    data.nextReview = now + 86400000;
  }

  srsData[card.term] = data;
  saveSRS();
  updateStatsStrip();

  // Auto-advance: "know" skips ahead immediately; "learning" keeps it in rotation
  if (rating === 'know') {
    // Brief green flash then advance
    const srsRow = document.getElementById('fcSrsRow');
    srsRow.classList.add('fc-srs-rated');
    setTimeout(() => {
      srsRow.classList.remove('fc-srs-rated');
      nextCard();
    }, 400);
  } else {
    nextCard();
  }
}

// ── Saved Cards ───────────────────────────
function toggleSaveCard(e) {
  e.stopPropagation(); // don't flip card
  const card = fcFiltered[fcIndex];
  if (!card) return;
  const term = card.term;

  if (savedCards.has(term)) {
    savedCards.delete(term);
  } else {
    savedCards.add(term);
    // pulse animation
    document.getElementById('fcSaveBtn').classList.add('fc-save-pulse');
    document.getElementById('fcSaveBtnBack').classList.add('fc-save-pulse');
    setTimeout(() => {
      document.getElementById('fcSaveBtn').classList.remove('fc-save-pulse');
      document.getElementById('fcSaveBtnBack').classList.remove('fc-save-pulse');
    }, 500);
  }
  saveSRS();
  updateSaveBtnUI();
  updateStatsStrip();

  // If viewing Saved ⭐ and we unsave, remove from current filtered list
  if (fcActiveCategory === 'Saved ⭐' && !savedCards.has(term)) {
    fcFiltered = fcFiltered.filter(f => f.term !== term);
    if (fcFiltered.length === 0) {
      filterFC('All');
      return;
    }
    if (fcIndex >= fcFiltered.length) fcIndex = fcFiltered.length - 1;
    updateFC();
    return;
  }
}

function updateSaveBtnUI() {
  const card = fcFiltered[fcIndex];
  if (!card) return;
  const saved = savedCards.has(card.term);
  ['fcSaveBtn', 'fcSaveBtnBack'].forEach(id => {
    const btn = document.getElementById(id);
    if (!btn) return;
    btn.textContent = saved ? '★' : '☆';
    btn.classList.toggle('fc-save-btn--active', saved);
  });
}

// ── SRS-aware next card selection ─────────
// When in "All" or any non-Saved category: prioritise 'learning' cards that are due
function getNextSRSIndex(currentIndex) {
  const now = Date.now();
  // Find due 'learning' cards first (excluding current)
  const dueIndices = fcFiltered
    .map((f, i) => ({ i, data: getCardData(f.term) }))
    .filter(({ i, data }) => i !== currentIndex && data.status === 'learning' && data.nextReview <= now)
    .map(({ i }) => i);

  if (dueIndices.length > 0) {
    // Pick the most overdue
    return dueIndices[Math.floor(Math.random() * Math.min(dueIndices.length, 3))];
  }

  // Otherwise just go to next sequentially
  if (currentIndex < fcFiltered.length - 1) return currentIndex + 1;
  return 0;
}

// ── Stats Strip ───────────────────────────
function updateStatsStrip() {
  const allTerms = flashcards.map(f => f.term);
  let know = 0, learning = 0, unseen = 0;
  allTerms.forEach(term => {
    const d = getCardData(term);
    if (d.status === 'know') know++;
    else if (d.status === 'learning') learning++;
    else unseen++;
  });
  document.getElementById('statKnow').textContent = know;
  document.getElementById('statLearning').textContent = learning;
  document.getElementById('statSaved').textContent = savedCards.size;
  document.getElementById('statUnseen').textContent = unseen;
}

// ── Rendering ────────────────────────────
function renderFCCategories() {
  const row = document.getElementById('fcCategories');
  row.innerHTML = allCategories.map(cat => `
    <button class="fc-cat-btn ${cat === fcActiveCategory ? 'active' : ''}" onclick="filterFC('${cat.replace(/'/g, "\\'")}')">${cat}</button>
  `).join('');
}

function filterFC(cat) {
  fcActiveCategory = cat;
  // Clear search if present
  const searchInput = document.getElementById('fcSearchInput');
  if (searchInput && searchInput.value) {
    searchInput.value = '';
    const clrBtn = document.getElementById('fcSearchClear');
    const resEl  = document.getElementById('fcSearchResults');
    if (clrBtn) clrBtn.classList.add('hidden');
    if (resEl)  { resEl.classList.add('hidden'); resEl.innerHTML = ''; }
  }

  if (cat === 'Saved ⭐') {
    fcFiltered = flashcards.filter(f => savedCards.has(f.term));
    if (fcFiltered.length === 0) {
      // Nothing saved yet — show friendly message
      fcFiltered = [{ term: 'No saved cards yet!', def: 'Tap the ☆ star on any flashcard to save it here for quick review.', cat: 'Saved ⭐' }];
    }
  } else if (cat === 'All') {
    // SRS-aware ordering: put due 'learning' cards first
    const now = Date.now();
    const due    = flashcards.filter(f => { const d = getCardData(f.term); return d.status === 'learning' && d.nextReview <= now; });
    const unseen = flashcards.filter(f => getCardData(f.term).status === 'unseen');
    const rest   = flashcards.filter(f => { const d = getCardData(f.term); return d.status === 'know' || (d.status === 'learning' && d.nextReview > now); });
    fcFiltered = [...due, ...unseen, ...rest];
  } else {
    fcFiltered = flashcards.filter(f => f.cat === cat);
  }

  fcIndex = 0;
  fcFlipped = false;
  renderFCCategories();
  updateFC();
}

function updateFC() {
  const card = fcFiltered[fcIndex];
  if (!card) return;

  document.getElementById('fcTerm').textContent = card.term;
  document.getElementById('fcDef').textContent = card.def;
  document.getElementById('fcCatTag').textContent = card.cat;
  document.getElementById('fcProgress').textContent = `${fcIndex + 1} / ${fcFiltered.length}`;
  document.getElementById('fcBarFill').style.width = `${((fcIndex + 1) / fcFiltered.length) * 100}%`;

  // Reset flip state
  fcFlipped = false;
  document.getElementById('fcInner').classList.remove('flipped');

  // Hide SRS row until card is flipped
  const srsRow = document.getElementById('fcSrsRow');
  srsRow.classList.remove('visible');

  // Update status indicator on card
  const data = getCardData(card.term);
  const progressBar = document.getElementById('fcBarFill');
  progressBar.className = 'fc-bar-fill';
  if (data.status === 'know') progressBar.classList.add('fc-bar-fill--know');
  else if (data.status === 'learning') progressBar.classList.add('fc-bar-fill--learning');

  updateSaveBtnUI();
  updateStatsStrip();
}

function flipCard() {
  fcFlipped = !fcFlipped;
  document.getElementById('fcInner').classList.toggle('flipped', fcFlipped);
  // Show SRS buttons once the card has been flipped at least once
  if (fcFlipped) {
    document.getElementById('fcSrsRow').classList.add('visible');
  }
}

function nextCard() {
  const next = getNextSRSIndex(fcIndex);
  fcIndex = next;
  updateFC();
}

function prevCard() {
  if (fcIndex > 0) fcIndex--;
  else fcIndex = fcFiltered.length - 1;
  updateFC();
}

// ── Flashcard Search ──────────────────────
function searchFC(query) {
  const clearBtn = document.getElementById('fcSearchClear');
  const resultsEl = document.getElementById('fcSearchResults');
  if (!clearBtn || !resultsEl) return;
  const q = query.trim().toLowerCase();
  clearBtn.classList.toggle('hidden', q.length === 0);
  if (q.length === 0) { resultsEl.classList.add('hidden'); resultsEl.innerHTML = ''; return; }

  const results = flashcards.filter(f =>
    f.term.toLowerCase().includes(q) ||
    f.def.toLowerCase().includes(q) ||
    f.cat.toLowerCase().includes(q)
  );

  if (results.length === 0) {
    resultsEl.innerHTML = `<div class="fc-search-empty">No results for "<strong>${escapeHtml(query)}</strong>"</div>`;
  } else {
    resultsEl.innerHTML = results.slice(0, 30).map(f => `
      <button class="fc-search-result-item" onclick="jumpToSearchResult(${flashcards.indexOf(f)})">
        <span class="fc-sri-cat">${f.cat}</span>
        <span class="fc-sri-term">${highlightMatch(f.term, q)}</span>
        <span class="fc-sri-def">${highlightMatch(f.def.length > 80 ? f.def.slice(0, 80) + '…' : f.def, q)}</span>
      </button>
    `).join('');
    if (results.length > 30) {
      resultsEl.innerHTML += `<div class="fc-search-more">Showing 30 of ${results.length} results — refine your search to narrow down.</div>`;
    }
  }
  resultsEl.classList.remove('hidden');
}

function jumpToSearchResult(cardIndex) {
  fcActiveCategory = 'All';
  fcFiltered = [...flashcards];
  fcIndex = cardIndex;
  fcFlipped = false;
  renderFCCategories();
  updateFC();
  document.getElementById('fcSearchInput').value = '';
  document.getElementById('fcSearchClear').classList.add('hidden');
  const resEl = document.getElementById('fcSearchResults');
  resEl.classList.add('hidden'); resEl.innerHTML = '';
  document.getElementById('flashcard').scrollIntoView({ behavior: 'smooth', block: 'center' });
}

function clearFCSearch() {
  document.getElementById('fcSearchInput').value = '';
  document.getElementById('fcSearchClear').classList.add('hidden');
  const resEl = document.getElementById('fcSearchResults');
  resEl.classList.add('hidden'); resEl.innerHTML = '';
}

function highlightMatch(text, query) {
  const escaped = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  return escapeHtml(text).replace(new RegExp(`(${escaped})`, 'gi'), '<mark>$1</mark>');
}

function escapeHtml(str) {
  return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

