var _aipConversation  = [];  // [{role, content}] — full history sent to API
var _aipCaseSecret    = null; // the hidden case the AI is playing
var _aipPatientInfo   = null; // {name, age, gender, avatar}
var _aipLoading       = false;
window._aipLastDiff   = 'beginner';

// Patient case prompts by difficulty
var AIP_CASE_POOLS = {
  beginner: [
    'acute appendicitis in a teenager', 'urinary tract infection in a young woman',
    'strep throat in a child', 'ankle sprain from sport', 'migraine headache',
    'chickenpox in a child', 'iron-deficiency anaemia', 'food poisoning',
    'simple febrile seizure in a toddler', 'otitis media in a toddler',
    'eczema flare in a child', 'hay fever', 'tension headache'
  ],
  intermediate: [
    'DVT in a long-haul traveller', 'atrial fibrillation', 'gout in a middle-aged man',
    'BPPV', 'peptic ulcer with GI bleed', 'hyperthyroidism (Graves disease)',
    'carpal tunnel syndrome', 'hypothyroidism', 'cellulitis',
    'spontaneous pneumothorax in a tall young male', 'testicular torsion',
    'rheumatoid arthritis', 'herniated disc with sciatica', 'COPD exacerbation',
    'ACL rupture', 'endometriosis'
  ],
  advanced: [
    'Addisonian crisis after stopping steroids', 'cardiac tamponade',
    'acute pancreatitis in an alcoholic', 'rhabdomyolysis after extreme exercise',
    'HOCM in a young athlete', 'hypercalcaemia of malignancy', 'acute angle-closure glaucoma',
    'carbon monoxide poisoning (whole family affected)', 'SIADH from lung cancer',
    'SLE in a young woman', 'giant cell arteritis with threatened vision',
    'severe aortic stenosis', 'thyroid storm'
  ],
  expert: [
    'TTP with microangiopathic haemolytic anaemia', 'posterior circulation stroke mimicking labyrinthitis',
    'heparin-induced thrombocytopaenia (HIT)', 'cerebral venous sinus thrombosis on OCP',
    'Wernicke encephalopathy in an alcoholic given dextrose without thiamine',
    'neuroleptic malignant syndrome', 'serotonin syndrome from SSRI + linezolid',
    'anti-NMDA receptor encephalitis', 'Long QT syndrome with exercise-induced syncope',
    'WPW with pre-excited AF', 'ARDS on the ventilator',
    'malignant hyperthermia in the operating theatre',
    'acute intermittent porphyria triggered by the OCP'
  ]
};

var AIP_AVATARS = {
  male:   ['👨', '👴', '🧑', '👦'],
  female: ['👩', '👵', '🧑', '👧']
};

function showAIPLobby() {
  document.getElementById('aip-lobby').style.display = '';
  document.getElementById('aip-room').style.display    = 'none';
  document.getElementById('aip-feedback').style.display = 'none';
}

function startAIConsultation(difficulty) {
  window._aipLastDiff = difficulty;

  // Pick a random case from the pool
  var pool = AIP_CASE_POOLS[difficulty] || AIP_CASE_POOLS.beginner;
  _aipCaseSecret = pool[Math.floor(Math.random() * pool.length)];

  // Generate a patient persona
  var gender  = Math.random() > 0.5 ? 'male' : 'female';
  var ageRanges = { beginner: [6,45], intermediate: [20,65], advanced: [30,75], expert: [25,80] };
  var r = ageRanges[difficulty] || [20, 60];
  var age = Math.floor(Math.random() * (r[1] - r[0])) + r[0];
  var maleNames   = ['James', 'David', 'Michael', 'Robert', 'William', 'John', 'Thomas', 'Daniel', 'Oliver', 'Harry'];
  var femaleNames = ['Sarah', 'Emma', 'Olivia', 'Sophie', 'Charlotte', 'Emily', 'Ava', 'Mia', 'Isabella', 'Grace'];
  var name    = gender === 'male'
    ? maleNames[Math.floor(Math.random() * maleNames.length)]
    : femaleNames[Math.floor(Math.random() * femaleNames.length)];
  var avatarPool = AIP_AVATARS[gender];
  var avatar     = avatarPool[Math.floor(Math.random() * avatarPool.length)];

  _aipPatientInfo = { name: name, age: age, gender: gender, avatar: avatar };
  _aipConversation = [];

  // Show room, hide lobby + feedback
  document.getElementById('aip-lobby').style.display    = 'none';
  document.getElementById('aip-feedback').style.display = 'none';
  document.getElementById('aip-room').style.display     = '';

  // Update patient card
  document.getElementById('aipAvatar').textContent      = avatar;
  document.getElementById('aipPatientName').textContent = name + ', ' + age;
  document.getElementById('aipPatientMeta').textContent =
    (gender === 'male' ? 'Male' : 'Female') + ' · ' + difficulty.charAt(0).toUpperCase() + difficulty.slice(1) + ' difficulty';

  // Clear chat + input
  document.getElementById('aipChat').innerHTML = '';
  document.getElementById('aipInput').value    = '';
  document.getElementById('aipDiagInput').value = '';

  // Opening message from patient
  var opener = name + ' walks into the consultation room and sits down, looking ' +
    (difficulty === 'beginner' ? 'worried' : difficulty === 'expert' ? 'quite unwell' : 'uncomfortable') + '.';
  addAIPSystemMsg(opener);

  // First AI message — patient introduces their chief complaint
  callAIPatient('(Start the consultation. Give a brief, realistic opening statement about why you are here today — 1-2 sentences, in character as the patient. Do not reveal the diagnosis. Be natural.)');
}

function addAIPSystemMsg(text) {
  var chat = document.getElementById('aipChat');
  var div  = document.createElement('div');
  div.style.cssText = 'text-align:center;font-size:12px;color:var(--grey-400);padding:4px 0;font-style:italic;';
  div.textContent = text;
  chat.appendChild(div);
  chat.scrollTop = chat.scrollHeight;
}

function addAIPMessage(role, text) {
  var chat = document.getElementById('aipChat');

  // Remove typing indicator if present
  var typing = document.getElementById('aipTyping');
  if (typing) typing.remove();

  var isDoctor  = role === 'doctor';
  var wrap      = document.createElement('div');
  wrap.className = 'aip-msg aip-msg--' + (isDoctor ? 'doctor' : 'patient');

  var avatarDiv = document.createElement('div');
  avatarDiv.className = 'aip-msg-avatar';
  avatarDiv.textContent = isDoctor ? '👨‍⚕️' : _aipPatientInfo.avatar;

  var bubble = document.createElement('div');
  bubble.className = 'aip-msg-bubble';
  bubble.textContent = text;

  wrap.appendChild(avatarDiv);
  wrap.appendChild(bubble);
  chat.appendChild(wrap);
  chat.scrollTop = chat.scrollHeight;
}

function showAIPTyping() {
  var chat = document.getElementById('aipChat');
  var wrap = document.createElement('div');
  wrap.id  = 'aipTyping';
  wrap.className = 'aip-msg aip-msg--patient aip-msg--typing';

  var avatarDiv = document.createElement('div');
  avatarDiv.className = 'aip-msg-avatar';
  avatarDiv.textContent = _aipPatientInfo ? _aipPatientInfo.avatar : '👤';

  var bubble = document.createElement('div');
  bubble.className = 'aip-msg-bubble';
  bubble.innerHTML = '<div class="aip-typing-dots"><span></span><span></span><span></span></div>';

  wrap.appendChild(avatarDiv);
  wrap.appendChild(bubble);
  chat.appendChild(wrap);
  chat.scrollTop = chat.scrollHeight;
}

function useAISuggestion(btn) {
  var input = document.getElementById('aipInput');
  input.value = btn.textContent;
  input.focus();
}

function aipKeydown(e) {
  // Send on Enter (not Shift+Enter)
  if (e.key === 'Enter' && !e.shiftKey) {
    e.preventDefault();
    sendAIPatientMessage();
  }
}

function sendAIPatientMessage() {
  if (_aipLoading) return;
  var input = document.getElementById('aipInput');
  var text  = input.value.trim();
  if (!text) return;

  input.value = '';
  addAIPMessage('doctor', text);
  callAIPatient(text);
}

function callAIPatient(userMessage) {
  _aipLoading = true;
  document.getElementById('aipSendBtn').disabled = true;
  showAIPTyping();

  // Build the system prompt
  var p = _aipPatientInfo;
  var systemPrompt = [
    'You are roleplaying as a PATIENT in a medical education consultation simulation.',
    'You are: ' + p.name + ', a ' + p.age + '-year-old ' + p.gender + '.',
    'The hidden medical condition you have is: ' + _aipCaseSecret + '.',
    '',
    'RULES:',
    '1. NEVER reveal your diagnosis or use medical jargon the patient would not know.',
    '2. Answer questions naturally as a real patient would — describe symptoms in lay terms.',
    '3. If asked to perform a physical examination (listen to chest, check BP, examine abdomen, etc.), respond AS THE NARRATOR describing the examination findings in 1-2 sentences, like: "Examination: [finding]".',
    '4. If asked about vitals, provide realistic values consistent with the condition.',
    '5. Be consistent — remember what you have said in this conversation.',
    '6. Keep responses SHORT — 1 to 4 sentences maximum. This is a consultation, not an essay.',
    '7. Show appropriate emotion — nervousness, pain, worry — based on the severity of the condition.',
    '8. If the student asks something irrelevant or rude, respond naturally as a patient would.',
    '9. Do NOT acknowledge you are an AI or that this is a simulation.',
  ].join('\n');

  // Build messages array
  var messages = _aipConversation.slice();
  messages.push({ role: 'user', content: userMessage });

  fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 300,
      system: systemPrompt,
      messages: messages
    })
  })
  .then(function(r) { return r.json(); })
  .then(function(data) {
    _aipLoading = false;
    document.getElementById('aipSendBtn').disabled = false;

    var reply = '';
    if (data.content && data.content[0] && data.content[0].text) {
      reply = data.content[0].text;
    } else {
      reply = 'Sorry, I didn\'t catch that. Could you repeat the question?';
    }

    // Add to conversation history (both sides)
    _aipConversation.push({ role: 'user',      content: userMessage });
    _aipConversation.push({ role: 'assistant', content: reply       });

    addAIPMessage('patient', reply);
  })
  .catch(function(err) {
    _aipLoading = false;
    document.getElementById('aipSendBtn').disabled = false;
    var typing = document.getElementById('aipTyping');
    if (typing) typing.remove();
    addAIPSystemMsg('Connection error — please check your internet and try again.');
    console.error('AIP error:', err);
  });
}

function submitAIDiagnosis() {
  var dx = document.getElementById('aipDiagInput').value.trim();
  if (!dx) {
    document.getElementById('aipDiagInput').focus();
    document.getElementById('aipDiagInput').style.borderColor = '#ef4444';
    setTimeout(function() { document.getElementById('aipDiagInput').style.borderColor = ''; }, 1500);
    return;
  }

  // Show loading in feedback area
  document.getElementById('aip-room').style.display     = 'none';
  document.getElementById('aip-feedback').style.display = '';
  document.getElementById('aip-feedback').innerHTML =
    '<div class="aip-loading-wrap"><div class="aip-loading-spinner"></div><div class="aip-loading-text">Reviewing your diagnosis…</div></div>';

  // Build a summary of what the student asked
  var questionsSummary = _aipConversation
    .filter(function(m) { return m.role === 'user'; })
    .map(function(m, i) { return (i + 1) + '. ' + m.content; })
    .join('\n');

  var feedbackPrompt = [
    'You are a medical education AI giving feedback to a student who just completed a patient consultation simulation.',
    '',
    'CASE: The patient had ' + _aipCaseSecret + '.',
    'STUDENT\'S DIAGNOSIS: ' + dx,
    '',
    'QUESTIONS THE STUDENT ASKED:',
    questionsSummary || '(No questions recorded)',
    '',
    'Give feedback in this EXACT format (use these exact headings):',
    '',
    'VERDICT: [Correct / Partially correct / Incorrect]',
    '',
    'FEEDBACK:',
    '[3-5 sentences: Was the diagnosis right? What did they do well in their questioning? What key questions were they missing? What should they study?]',
    '',
    'KEY LEARNING POINTS:',
    '[2-3 bullet points with the most important clinical teaching points about this condition]',
    '',
    'Be encouraging but honest. This is for a student — use simple language.',
  ].join('\n');

  fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 600,
      messages: [{ role: 'user', content: feedbackPrompt }]
    })
  })
  .then(function(r) { return r.json(); })
  .then(function(data) {
    var text = (data.content && data.content[0] && data.content[0].text) || 'Could not generate feedback.';

    // Parse verdict
    var verdictMatch = text.match(/VERDICT:\s*(.+)/i);
    var verdict      = verdictMatch ? verdictMatch[1].trim() : 'Reviewed';
    var isCorrect    = /correct/i.test(verdict) && !/partially|incorrect/i.test(verdict);
    var isPartial    = /partially/i.test(verdict);

    var verdictEmoji = isCorrect ? '✅ Correct!' : isPartial ? '⚡ Close!' : '❌ Not quite';
    var verdictColour = isCorrect ? '#166534' : isPartial ? '#92400e' : '#991b1b';

    // Parse sections
    var feedbackMatch = text.match(/FEEDBACK:\s*([\s\S]*?)(?=KEY LEARNING|$)/i);
    var keyMatch      = text.match(/KEY LEARNING POINTS:\s*([\s\S]*)/i);
    var feedbackText  = feedbackMatch ? feedbackMatch[1].trim() : text;
    var keyPoints     = keyMatch     ? keyMatch[1].trim()     : '';

    // Build HTML
    var summaryHTML = _aipConversation
      .filter(function(m) { return m.role === 'user'; })
      .slice(0, 8)
      .map(function(m, i) { return '<div style="padding:2px 0">' + (i+1) + '. ' + escapeHTML(m.content) + '</div>'; })
      .join('');

    var card = document.createElement('div');
    card.className = 'aip-feedback-card';
    card.innerHTML = [
      '<div class="aip-feedback-verdict" style="color:' + verdictColour + '">' + verdictEmoji + '</div>',
      '<div class="aip-feedback-correct">',
        '<span class="aip-feedback-label">Correct diagnosis:</span>',
        '<span class="aip-feedback-answer">' + escapeHTML(_aipCaseSecret.charAt(0).toUpperCase() + _aipCaseSecret.slice(1)) + '</span>',
      '</div>',
      '<div class="aip-feedback-body">' + escapeHTML(feedbackText) + '</div>',
      keyPoints ? '<div class="aip-feedback-body" style="background:var(--grey-50);border:1.5px solid var(--grey-100);border-radius:10px;padding:14px 16px"><strong style="color:var(--navy);font-size:13px">📚 Key Learning Points</strong><br><br>' + escapeHTML(keyPoints) + '</div>' : '',
      '<div class="aip-feedback-history">',
        '<div class="aip-feedback-hist-title">📋 Questions you asked (' + Math.floor(_aipConversation.length / 2) + ' exchanges)</div>',
        '<div id="aipHistorySummary">' + (summaryHTML || '<em style="color:var(--grey-400)">No questions recorded</em>') + '</div>',
      '</div>',
      '<div class="aip-feedback-actions">',
        '<button class="btn-primary" onclick="startAIConsultation(window._aipLastDiff)">Try Another Case</button>',
        '<button class="btn-outline" onclick="showAIPLobby()">Change Difficulty</button>',
      '</div>'
    ].join('');

    document.getElementById('aip-feedback').innerHTML = '';
    document.getElementById('aip-feedback').appendChild(card);
  })
  .catch(function(err) {
    document.getElementById('aip-feedback').innerHTML =
      '<div class="aip-feedback-card"><div class="aip-feedback-verdict" style="color:#ef4444">Connection Error</div>' +
      '<div class="aip-feedback-body">Could not get feedback. Please check your internet connection.</div>' +
      '<div class="aip-feedback-actions"><button class="btn-outline" onclick="showAIPLobby()">Back</button></div></div>';
    console.error('Feedback error:', err);
  });
}

function escapeHTML(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}
